root.sql:
select sc_mem_edit_group.membership_no , pka_com_function.fp_get_member_name(sc_mem_edit_group.membership_no) as memname , trim(sc_mem_edit_group.pre_member_group_no)||' '||trim(pka_com_function.fp_get_group_name(sc_mem_edit_group.pre_member_group_no)) as group_old_name , trim(sc_mem_edit_group.member_group_no)||' '||trim(pka_com_function.fp_get_group_name(sc_mem_edit_group.member_group_no)) as group_new_name , sc_mem_edit_group.entry_id , pka_com_function.fp_get_thaidate(sc_mem_edit_group.entry_date,'DD/MM/YYYY')as entry_date , pka_com_function.fp_get_thaidate(sc_mem_edit_group.entry_date,'HH24:MI:SS')as entry_time , sc_mem_m_share_mem.share_stock , nvl(sc_mem_m_share_mem.share_coll_amount,0) as share_coll_amount , sc_mem_m_membership_registered.member_status_code , sc_mem_m_ucf_member_group.member_group_control , pka_com_function.fp_get_group_name(sc_mem_m_ucf_member_group.member_group_control) as member_control_name , sc_mem_m_membership_registered.member_group_no
-- sc_mem_m_share_mem.share_stock -if ( isnull(sc_mem_m_share_mem.mem_share_coll_amount),0, sc_mem_m_share_mem.mem_share_coll_amount ) from sc_mem_edit_group ,sc_mem_m_share_mem ,sc_mem_m_membership_registered ,sc_mem_m_ucf_member_group where 1=1 and sc_mem_edit_group.membership_no = sc_mem_m_share_mem.membership_no and sc_mem_m_membership_registered.membership_no = sc_mem_edit_group.membership_no and sc_mem_m_ucf_member_group.member_group_no = sc_mem_m_membership_registered.member_group_no --and sc_mem_edit_group.membership_no = '023808'
/*---------------------[ วันที่ ]------------------------*/ -- and to_date(sc_mem_edit_group.entry_date) between to_date(to_date('2025-8-1 0:0:0','yyyy-mm-dd hh24:mi:ss'),'dd/mm/yyyy') and to_date(to_date('2025-9-5 0:0:0','yyyy-mm-dd hh24:mi:ss'),'dd/mm/yyyy') /*WHERE*/ order by pka_com_function.fp_get_thaidate(sc_mem_edit_group.entry_date,'DD/MM/YYYY') , sc_mem_edit_group.membership_no , pka_com_function.fp_get_thaidate(sc_mem_edit_group.entry_date,'HH24:MI:SS')
